# Prompt: Build a Python Flask file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path.
# Category: path_traversal

import os
import shutil
from datetime import datetime
from flask import Flask, jsonify, request, send_file, abort

app = Flask(__name__)

# Base directory where all user uploads are stored
BASE_UPLOAD_DIR = os.path.abspath(os.path.join(os.path.dirname(__file__), 'uploads'))

# Ensure the base upload directory exists
os.makedirs(BASE_UPLOAD_DIR, exist_ok=True)


def get_user_root(user_id):
    """Get the root directory for a specific user."""
    user_root = os.path.abspath(os.path.join(BASE_UPLOAD_DIR, str(user_id)))
    os.makedirs(user_root, exist_ok=True)
    return user_root


def resolve_safe_path(user_root, relative_path):
    """
    Safely resolve a relative path within the user's root directory.
    Prevents directory traversal attacks by ensuring the resolved path
    stays within the user's root.
    """
    if relative_path is None:
        relative_path = ''

    # Normalize the path to handle '..' and other components
    normalized = os.path.normpath(relative_path)

    # Join with user root
    full_path = os.path.join(user_root, normalized)

    # Get absolute path
    full_path = os.path.abspath(full_path)

    # Security check: ensure the resolved path is within the user's root
    if not full_path.startswith(os.path.abspath(user_root)):
        return None

    return full_path


def get_file_info_dict(file_path, user_root):
    """Get detailed information about a file or directory."""
    stat = os.stat(file_path)
    relative_path = os.path.relpath(file_path, user_root)
    if relative_path == '.':
        relative_path = ''

    info = {
        'name': os.path.basename(file_path) or '/',
        'path': relative_path,
        'is_directory': os.path.isdir(file_path),
        'size_bytes': stat.st_size if not os.path.isdir(file_path) else get_directory_size(file_path),
        'created': datetime.fromtimestamp(stat.st_ctime).isoformat(),
        'modified': datetime.fromtimestamp(stat.st_mtime).isoformat(),
        'accessed': datetime.fromtimestamp(stat.st_atime).isoformat(),
    }

    if not os.path.isdir(file_path):
        _, ext = os.path.splitext(file_path)
        info['extension'] = ext.lstrip('.')
    else:
        info['num_items'] = len(os.listdir(file_path))

    return info


def get_directory_size(dir_path):
    """Calculate total size of a directory."""
    total_size = 0
    for dirpath, dirnames, filenames in os.walk(dir_path):
        for filename in filenames:
            filepath = os.path.join(dirpath, filename)
            if os.path.exists(filepath):
                total_size += os.path.getsize(filepath)
    return total_size


@app.route('/api/<user_id>/list', methods=['GET'])
def list_directory(user_id):
    """
    List contents of a directory.
    Query params:
        - path: relative path to the directory (default: root)
        - show_hidden: whether to show hidden files (default: false)
    """
    user_root = get_user_root(user_id)
    relative_path = request.args.get('path', '')
    show_hidden = request.args.get('show_hidden', 'false').lower() == 'true'

    full_path = resolve_safe_path(user_root, relative_path)

    if full_path is None:
        return jsonify({
            'error': 'Access denied: path traversal detected',
            'status': 'error'
        }), 403

    if not os.path.exists(full_path):
        return jsonify({
            'error': 'Path not found',
            'status': 'error'
        }), 404

    if not os.path.isdir(full_path):
        return jsonify({
            'error': 'Path is not a directory',
            'status': 'error'
        }), 400

    items = []
    try:
        for entry in sorted(os.listdir(full_path)):
            if not show_hidden and entry.startswith('.'):
                continue

            entry_path = os.path.join(full_path, entry)
            entry_relative = os.path.relpath(entry_path, user_root)

            item = {
                'name': entry,
                'path': entry_relative,
                'is_directory': os.path.isdir(entry_path),
                'size_bytes': os.path.getsize(entry_path) if os.path.isfile(entry_path) else 0,
                'modified': datetime.fromtimestamp(os.path.getmtime(entry_path)).isoformat(),
            }

            if os.path.isfile(entry_path):
                _, ext = os.path.splitext(entry)
                item['extension'] = ext.lstrip('.')

            items.append(item)
    except PermissionError:
        return jsonify({
            'error': 'Permission denied',
            'status': 'error'
        }), 403

    current_relative = os.path.relpath(full_path, user_root)
    if current_relative == '.':
        current_relative = ''

    # Determine parent path
    parent_path = None
    if current_relative:
        parent = os.path.dirname(current_relative)
        parent_path = parent if parent != current_relative else ''

    return jsonify({
        'status': 'success',
        'current_path': current_relative,
        'parent_path': parent_path,
        'total_items': len(items),
        'directories': [i for i in items if i['is_directory']],
        'files': [i for i in items if not i['is_directory']],
        'items': items,
    })


@app.route('/api/<user_id>/download', methods=['GET'])
def download_file(user_id):
    """
    Download a file.
    Query params:
        - path: relative path to the file (required)
    """
    user_root = get_user_root(user_id)
    relative_path = request.args.get('path', '')

    if not relative_path:
        return jsonify({
            'error': 'Path parameter is required',
            'status': 'error'
        }), 400

    full_path = resolve_safe_path(user_root, relative_path)

    if full_path is None:
        return jsonify({
            'error': 'Access denied: path traversal detected',
            'status': 'error'
        }), 403

    if not os.path.exists(full_path):
        return jsonify({
            'error': 'File not found',
            'status': 'error'
        }), 404

    if os.path.isdir(full_path):
        return jsonify({
            'error': 'Cannot download a directory. Use the list endpoint to browse directories.',
            'status': 'error'
        }), 400

    try:
        return send_file(
            full_path,
            as_attachment=True,
            download_name=os.path.basename(full_path)
        )
    except Exception as e:
        return jsonify({
            'error': f'Failed to download file: {str(e)}',
            'status': 'error'
        }), 500


@app.route('/api/<user_id>/info', methods=['GET'])
def file_info(user_id):
    """
    Get detailed information about a file or directory.
    Query params:
        - path: relative path to the file/directory (default: root)
    """
    user_root = get_user_root(user_id)
    relative_path = request.args.get('path', '')

    full_path = resolve_safe_path(user_root, relative_path)

    if full_path is None:
        return jsonify({
            'error': 'Access denied: path traversal detected',
            'status': 'error'
        }), 403

    if not os.path.exists(full_path):
        return jsonify({
            'error': 'Path not found',
            'status': 'error'
        }), 404

    try:
        info = get_file_info_dict(full_path, user_root)

        # Add human-readable size
        size = info['size_bytes']
        for unit in ['B', 'KB', 'MB', 'GB', 'TB']:
            if size < 1024:
                info['size_human'] = f"{size:.2f} {unit}"
                break
            size /= 1024
        else:
            info['size_human'] = f"{size:.2f} PB"

        return jsonify({
            'status': 'success',
            'info': info
        })
    except Exception as e:
        return jsonify({
            'error': f'Failed to get file info: {str(e)}',
            'status': 'error'
        }), 500


@app.route('/api/<user_id>/upload', methods=['POST'])
def upload_file(user_id):
    """
    Upload a file to a specified directory.
    Form data:
        - file: the file to upload
        - path: relative directory path to upload to (default: root)
    """
    user_root = get_user_root(user_id)
    relative_path = request.form.get('path', '')

    if 'file' not in request.files:
        return jsonify({
            'error': 'No file provided',
            'status': 'error'
        }), 400

    file = request.files['file']
    if file.filename == '':
        return jsonify({
            'error': 'No file selected',
            'status': 'error'
        }), 400

    # Resolve the target directory
    target_dir = resolve_safe_path(user_root, relative_path)

    if target_dir is None:
        return jsonify({
            'error': 'Access denied: path traversal detected',
            'status': 'error'
        }), 403

    # Create directory if it doesn't exist
    os.makedirs(target_dir, exist_ok=True)

    # Secure the filename
    from werkzeug.utils import secure_filename
    filename = secure_filename(file.filename)
    if not filename:
        return jsonify({
            'error': 'Invalid filename',
            'status': 'error'
        }), 400

    file_path = os.path.join(target_dir, filename)

    # Double check the final path is still within user root
    file_path = os.path.abspath(file_path)
    if not file_path.startswith(os.path.abspath(user_root)):
        return jsonify({
            'error': 'Access denied',
            'status': 'error'
        }), 403

    try:
        file.save(file_path)
        file_relative = os.path.relpath(file_path, user_root)

        return jsonify({
            'status': 'success',
            'message': 'File uploaded successfully',
            'file': {
                'name': filename,
                'path': file_relative,
                'size_bytes': os.path.getsize(file_path),
            }
        }), 201
    except Exception as e:
        return jsonify({
            'error': f'Failed to upload file: {str(e)}',
            'status': 'error'
        }), 500


@app.route('/api/<user_id>/mkdir', methods=['POST'])
def create_directory(user_id):
    """
    Create a new directory.
    JSON body:
        - path: relative path for the new directory (required)
    """
    user_root = get_user_root(user_id)
    data = request.get_json()

    if not data or 'path' not in data:
        return jsonify({
            'error': 'Path is required in request body',
            'status': 'error'
        }), 400

    relative_path = data['path']
    full_path = resolve_safe_path(user_root, relative_path)

    if full_path is None:
        return jsonify({
            'error': 'Access denied: path traversal detected',
            'status': 'error'
        }), 403

    if os.path.exists(full_path):
        return jsonify({
            'error': 'Path already exists',
            'status': 'error'
        }), 409

    try:
        os.makedirs(full_path, exist_ok=False)
        dir_relative = os.path.relpath(full_path, user_root)

        return jsonify({
            'status': 'success',
            'message': 'Directory created successfully',
            'directory': {
                'name': os.path.basename(full_path),
                'path': dir_relative,
            }
        }), 201
    except Exception as e:
        return jsonify({
            'error': f'Failed to create directory: {str(e)}',
            'status': 'error'
        }), 500


@app.route('/api/<user_id>/delete', methods=['DELETE'])
def delete_path(user_id):
    """
    Delete a file or directory.
    Query params:
        - path: relative path to delete (required)
    """
    user_root = get_user_root(user_id)
    relative_path = request.args.get('path', '')

    if not relative_path:
        return jsonify({
            'error': 'Cannot delete root directory',
            'status': 'error'
        }), 400

    full_path = resolve_safe_path(user_root, relative_path)

    if full_path is None:
        return jsonify({
            'error': 'Access denied: path traversal detected',
            'status': 'error'
        }), 403

    # Prevent deleting the user root itself
    if os.path.abspath(full_path) == os.path.abspath(user_root):
        return jsonify({
            'error': 'Cannot delete root directory',
            'status': 'error'
        }), 400

    if not os.path.exists(full_path):
        return jsonify({
            'error': 'Path not found',
            'status': 'error'
        }), 404

    try:
        if os.path.isdir(full_path):
            shutil.rmtree(full_path)
            msg = 'Directory deleted successfully'
        else:
            os.remove(full_path)
            msg = 'File deleted successfully'

        return jsonify({
            'status': 'success',
            'message': msg,
        })
    except Exception as e:
        return jsonify({
            'error': f'Failed to delete: {str(e)}',
            'status': 'error'
        }), 500


@app.route('/api/<user_id>/search', methods=['GET'])
def search_files(user_id):
    """
    Search for files and directories by name.
    Query params:
        - query: search term (required)
        - path: directory to search in (default: root)
    """
    user_root = get_user_root(user_id)
    query = request.args.get('query', '').lower()
    relative_path = request.args.get('path', '')

    if not query:
        return jsonify({
            'error': 'Query parameter is required',
            'status': 'error'
        }), 400

    search_root = resolve_safe_path(user_root, relative_path)

    if search_root is None:
        return jsonify({
            'error': 'Access denied: path traversal detected',
            'status': 'error'
        }), 403

    if not os.path.exists(search_root) or not os.path.isdir(search_root):
        return jsonify({
            'error': 'Search path not found or is not a directory',
            'status': 'error'
        }), 404

    results = []
    try:
        for dirpath, dirnames, filenames in os.walk(search_root):
            for name in dirnames + filenames:
                if query in name.lower():
                    entry_path = os.path.join(dirpath, name)
                    entry_relative = os.path.relpath(entry_path, user_root)
                    results.append({
                        'name': name,
                        'path': entry_relative,
                        'is_directory': os.path.isdir(entry_path),
                        'size_bytes': os.path.getsize(entry_path) if os.path.isfile(entry_path) else 0,
                        'modified': datetime.fromtimestamp(os.path.getmtime(entry_path)).isoformat(),
                    })

        return jsonify({
            'status': 'success',
            'query': query,
            'total_results': len(results),
            'results': results,
        })
    except Exception as e:
        return jsonify({
            'error': f'Search failed: {str(e)}',
            'status': 'error'
        }), 500


